#!/usr/bin/env python3
"""Source adapters and CLI boundary for verified ModuFlow review intake."""

import argparse
import copy
import json
import sys
from datetime import date
from pathlib import Path

if __package__ in (None, ""):
    sys.path.insert(0, str(Path(__file__).resolve().parent.parent))

from scripts import review_intake as ri


ADAPTER_ORDER = [
    "manual-review-document",
    "github-review",
    "security-review",
    "superpowers-review",
    "spec-kit",
]
SENSITIVE_PARTS = {
    "auth",
    "permission",
    "payment",
    "billing",
    "secret",
    "upload",
    "deploy",
    ".github/workflows",
}
SARIF_LEVEL_TO_SEVERITY = {
    "error": "high",
    "warning": "medium",
    "note": "low",
    "none": "low",
}


def select_adapters(
    event,
    adapter,
    changed_paths,
    requires_plan=False,
    security_requested=False,
):
    paths = [str(path).lower() for path in changed_paths]
    sensitive = any(
        any(part in path for part in SENSITIVE_PARTS) for path in paths
    )
    if event == "routine" and not any(
        (adapter, sensitive, requires_plan, security_requested)
    ):
        return {
            "invoked": [],
            "skipped": ADAPTER_ORDER.copy(),
            "reason_codes": ["l0_routine"],
        }

    invoked = set()
    reasons = []
    if adapter == "manual":
        invoked.update({"manual-review-document", "superpowers-review"})
        reasons.append("manual_source")
    elif adapter == "github":
        invoked.update({"github-review", "superpowers-review"})
        reasons.append("pr_threads_present")
    elif adapter in {"sarif", "codeql"}:
        invoked.update({"security-review", "superpowers-review"})
        reasons.append("security_payload")

    if sensitive:
        invoked.update({"security-review", "superpowers-review"})
        reasons.append("sensitive_path")
    if security_requested:
        invoked.update({"security-review", "superpowers-review"})
        reasons.append("router_security_request")
    if requires_plan:
        invoked.add("spec-kit")
        reasons.append("planning_required")

    return {
        "invoked": [name for name in ADAPTER_ORDER if name in invoked],
        "skipped": [name for name in ADAPTER_ORDER if name not in invoked],
        "reason_codes": reasons,
    }


def adapt_manual_findings(payload):
    findings = payload.get("findings") if isinstance(payload, dict) else payload
    if not isinstance(findings, list):
        raise ri.ReviewIntakeError(
            "manual_findings_invalid",
            "manual adapter requires a findings list",
        )
    return copy.deepcopy(findings)


def _thread_comments(thread):
    comment_field = thread.get("comments") or []
    if isinstance(comment_field, dict):
        return comment_field.get("nodes") or []
    return comment_field


def adapt_github_threads(payload):
    findings = []
    for thread in payload.get("threads", []):
        if thread.get("isResolved") or thread.get("isOutdated"):
            continue
        comments = _thread_comments(thread)
        if not comments:
            continue
        comment = comments[-1]
        observation = str(comment.get("body") or "").strip()
        if not observation:
            continue
        author = comment.get("author") or {}
        login = author.get("login", "unknown")
        author_kind = (
            "ai"
            if author.get("type") == "Bot" or login.endswith("[bot]")
            else "human"
        )
        findings.append(
            {
                "rule_id": f"github-thread:{thread.get('id')}",
                "observation": observation,
                "recommendation": "",
                "root_cause_hypothesis": "",
                "locations": [
                    {
                        "path": thread.get("path"),
                        "line": thread.get("line"),
                        "anchor": thread.get("diffSide") or "",
                    }
                ],
                "source_author": {
                    "kind": author_kind,
                    "identity": login,
                },
                "provider_fingerprint": f"github-thread:{thread.get('id')}",
                "provider_evidence": {
                    "kind": "review",
                    "format": "github-thread",
                    "id": thread.get("id"),
                    "resolved": False,
                    "outdated": False,
                },
            }
        )
    return findings


def _sarif_location(result):
    locations = result.get("locations") or []
    physical = (locations[0].get("physicalLocation") or {}) if locations else {}
    artifact = physical.get("artifactLocation") or {}
    region = physical.get("region") or {}
    return {
        "path": artifact.get("uri"),
        "line": region.get("startLine"),
        "anchor": result.get("ruleId") or "",
    }


def _sarif_severity(result):
    properties = result.get("properties") or {}
    raw = str(
        properties.get("severity")
        or properties.get("security-severity")
        or result.get("level")
        or "error"
    ).lower()
    if raw in ri.SEVERITIES:
        return raw
    return SARIF_LEVEL_TO_SEVERITY.get(raw, "high")


def adapt_sarif(payload):
    findings = []
    for run in payload.get("runs", []):
        driver = (run.get("tool") or {}).get("driver") or {}
        for result in run.get("results", []):
            partials = result.get("partialFingerprints") or {}
            findings.append(
                {
                    "rule_id": result.get("ruleId"),
                    "observation": (result.get("message") or {}).get("text", ""),
                    "recommendation": "",
                    "root_cause_hypothesis": "",
                    "locations": [_sarif_location(result)],
                    "severity": _sarif_severity(result),
                    "source_author": {
                        "kind": "tool",
                        "identity": driver.get("name", "unknown"),
                        "version": driver.get("version"),
                    },
                    "provider_fingerprint": partials.get(
                        "primaryLocationLineHash"
                    )
                    or next(iter(partials.values()), None),
                    "provider_evidence": {
                        "kind": "security",
                        "format": "sarif",
                        "tool": driver.get("name"),
                        "version": driver.get("version"),
                    },
                }
            )
    return findings


def adapt_codeql_alerts(payload):
    alerts = payload.get("alerts") if isinstance(payload, dict) else payload
    if not isinstance(alerts, list):
        raise ri.ReviewIntakeError(
            "codeql_alerts_invalid",
            "CodeQL adapter requires an alerts list",
        )
    findings = []
    for alert in alerts:
        rule = alert.get("rule") or {}
        instance = alert.get("most_recent_instance") or {}
        location = instance.get("location") or {}
        raw_severity = str(
            rule.get("security_severity_level")
            or rule.get("severity")
            or "high"
        ).lower()
        severity = (
            raw_severity
            if raw_severity in ri.SEVERITIES
            else SARIF_LEVEL_TO_SEVERITY.get(raw_severity, "high")
        )
        number = alert.get("number")
        tool = alert.get("tool") or {}
        findings.append(
            {
                "rule_id": rule.get("id"),
                "observation": rule.get("description")
                or rule.get("name")
                or "Code scanning alert",
                "recommendation": "",
                "root_cause_hypothesis": "",
                "locations": [
                    {
                        "path": location.get("path"),
                        "line": location.get("start_line"),
                        "anchor": rule.get("id") or "",
                    }
                ],
                "severity": severity,
                "source_author": {
                    "kind": "tool",
                    "identity": tool.get("name", "CodeQL"),
                    "version": tool.get("version"),
                },
                "provider_fingerprint": f"codeql-alert:{number}",
                "provider_evidence": {
                    "kind": "security",
                    "format": "codeql-alert",
                    "number": number,
                    "state": alert.get("state"),
                    "dismissed_reason": alert.get("dismissed_reason"),
                    "dismissed_comment": alert.get("dismissed_comment"),
                    "dismissed_by": (alert.get("dismissed_by") or {}).get(
                        "login"
                    ),
                    "dismissed_at": alert.get("dismissed_at"),
                },
            }
        )
    return findings


def _load_json(path):
    return json.loads(Path(path).read_text(encoding="utf-8"))


def _public_packet(packet):
    visible = copy.deepcopy(packet)
    source = visible.get("source") or {}
    if "copied_text" in source:
        source["copied_text"] = "<retained-in-packet-redacted-from-output>"
    return visible


def render_summary_ko(packet):
    source = packet["source"]
    target = packet["target"]
    lines = [
        f"# 코드리뷰 접수: {packet['review_id']}",
        "",
        "## 출처",
        "",
        f"- 유형: `{source['kind']}`",
        f"- 제공자: `{source['provider']}`",
        f"- 작성자/도구: `{source.get('identity', 'unknown')}`",
        f"- 보관: `{source['retention']}`",
        f"- 대상: `{target['repository']}@{target['commit'][:12]}`",
        "",
        "## 어댑터 실행",
        "",
        "- 호출: "
        + (", ".join(packet.get("adapter_run", {}).get("invoked", [])) or "없음"),
        "- 생략: "
        + (", ".join(packet.get("adapter_run", {}).get("skipped", [])) or "없음"),
        "",
        "## Finding",
        "",
    ]
    for finding in packet["findings"]:
        provider = finding.get("provider_evidence") or {}
        lines.extend(
            [
                f"### {finding['id']} — {finding['risk']['severity']}",
                "",
                f"- 관찰: {finding['observation']}",
                f"- 권장: {finding['recommendation'] or '없음'}",
                f"- 원인 가설: {finding['root_cause_hypothesis'] or '없음'}",
                f"- 리뷰어 확신도: `{finding['reviewer_confidence']}`",
                f"- 검증 상태: `{finding['verification']['state']}`",
                f"- 판정: `{finding['disposition']['state']}`",
                f"- 경로: `{finding['route']['lane'] or '미정'}`",
                f"- Provider 상태: `{provider.get('state', '해당 없음')}`",
                f"- Provider dismiss 사유: `{provider.get('dismissed_reason', '해당 없음')}`",
                "",
            ]
        )
    return "\n".join(lines).rstrip() + "\n"


def render_candidate_queue(candidates):
    lines = ["# Review Candidates", ""]
    for item in candidates:
        overlap = (
            ", ".join(
                hint["issue_id"] for hint in item.get("overlap_hints", [])
            )
            or "없음"
        )
        reasons = ", ".join(item.get("routing_reason_codes", [])) or "없음"
        lines.extend(
            [
                f"## {item['id']} — {item['title']}",
                "",
                f"- State: `{item['state']}`",
                f"- Lane: `{item['lane']}`",
                f"- Priority: `{item['priority']}`",
                f"- CognitiveDemand: `{item['CognitiveDemand']}`",
                f"- Findings: {', '.join(item['finding_ids'])}",
                f"- Routing reasons: {reasons}",
                f"- Overlap hints: {overlap}",
                f"- Next: `{item['next_command']}`",
                "",
            ]
        )
    return "\n".join(lines).rstrip() + "\n"


def _write_text_atomic(path, text):
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    temporary = path.with_suffix(path.suffix + ".tmp")
    temporary.write_text(text, encoding="utf-8")
    temporary.replace(path)


def _packet_files(root):
    return sorted(
        (Path(root).resolve() / "workspace" / "reviews").glob("*.json")
    )


def _existing_candidates(root, exclude_review_id):
    candidates = []
    for path in _packet_files(root):
        try:
            packet = _load_json(path)
        except (OSError, json.JSONDecodeError):
            continue
        if packet.get("review_id") != exclude_review_id:
            candidates.extend(packet.get("candidates") or [])
    return candidates


def _add_overlap_hints(root, candidates):
    from scripts.project_intake import find_related_issues

    enriched = copy.deepcopy(candidates)
    for candidate in enriched:
        candidate["overlap_hints"] = find_related_issues(
            root, candidate["title"] + "\n" + candidate["problem"]
        )[:3]
    return enriched


def write_review_artifacts(root, packet):
    root = Path(root).resolve()
    reviews = root / "workspace" / "reviews"
    existing = _existing_candidates(root, packet["review_id"])
    candidate_result = ri.build_candidates(
        packet, existing_candidates=existing
    )
    stored = copy.deepcopy(packet)
    stored["candidates"] = _add_overlap_hints(
        root, candidate_result["candidates"]
    )
    stored["trace"] = candidate_result["trace"]
    for finding in stored["findings"]:
        finding["route"]["candidate_ids"] = stored["trace"][
            "finding_to_candidates"
        ].get(finding["id"], [])

    errors = ri.validate_packet(stored)
    if errors:
        raise ri.ReviewIntakeError(errors[0]["code"], errors[0]["message"])

    packet_path = reviews / f"{stored['review_id']}.json"
    summary_path = reviews / f"{stored['review_id']}.md"
    candidate_path = root / "workspace" / "review-candidates.md"
    _write_text_atomic(
        packet_path,
        json.dumps(stored, ensure_ascii=False, indent=2) + "\n",
    )
    _write_text_atomic(summary_path, render_summary_ko(stored))
    all_candidates = _existing_candidates(root, stored["review_id"]) + stored[
        "candidates"
    ]
    _write_text_atomic(candidate_path, render_candidate_queue(all_candidates))
    return {
        "packet": packet_path,
        "summary": summary_path,
        "candidates": candidate_path,
    }


def _required_new_args(args):
    required = {
        "review_id": args.review_id,
        "adapter": args.adapter,
        "source": args.source,
        "source_kind": args.source_kind,
        "target_repository": args.target_repository,
        "target_commit": args.target_commit,
    }
    missing = [name for name, value in required.items() if not value]
    if missing:
        raise ri.ReviewIntakeError(
            "usage_error",
            "missing required arguments: " + ", ".join(missing),
        )


def _adapt_new_source(args):
    if args.adapter == "manual":
        if not args.findings_file:
            raise ri.ReviewIntakeError(
                "manual_findings_missing",
                "manual adapter requires --findings-file",
            )
        return adapt_manual_findings(_load_json(args.findings_file))
    if args.adapter == "github":
        return adapt_github_threads(_load_json(args.source))
    if args.adapter == "sarif":
        return adapt_sarif(_load_json(args.source))
    return adapt_codeql_alerts(_load_json(args.source))


def run_new_intake(root, args):
    _required_new_args(args)
    source_path = Path(args.source)
    copied_text = (
        source_path.read_text(encoding="utf-8")
        if args.retention == "copy" and source_path.is_file()
        else None
    )
    source = ri.build_source_record(
        args.source_kind,
        args.provider,
        args.source_identity,
        args.received_at,
        args.retention,
        locator=args.source,
        copied_text=copied_text,
        source_hash=args.source_hash,
    )
    raw_findings = _adapt_new_source(args)
    trigger_event = {
        "manual": "manual_intake",
        "github": "pr_review",
        "sarif": "security_alert",
        "codeql": "security_alert",
    }[args.adapter]
    requires_plan = any(
        (item.get("router") or {}).get("requires_plan")
        for item in raw_findings
    )
    security_requested = any(
        (item.get("router") or {}).get("classification") == "security"
        for item in raw_findings
    )
    changed_paths = [
        location.get("path", "")
        for item in raw_findings
        for location in item.get("locations", [])
    ]
    adapter_run = select_adapters(
        trigger_event,
        args.adapter,
        changed_paths,
        requires_plan=requires_plan,
        security_requested=security_requested,
    )
    packet = ri.new_packet(
        args.review_id,
        source,
        {
            "repository": args.target_repository,
            "commit": args.target_commit,
            "base_branch": args.base_branch,
        },
        {"event": trigger_event, "reason_codes": ["review_received"]},
        adapter_run,
        raw_findings,
    )
    if not args.write:
        return {"action": "preview", "packet": _public_packet(packet)}
    paths = write_review_artifacts(root, packet)
    return {
        "action": "written",
        "packet": _public_packet(packet),
        "paths": {key: str(value) for key, value in paths.items()},
    }


def _verify_reference_integrity(packet):
    source = packet.get("source") or {}
    locator = Path(str(source.get("locator") or ""))
    if source.get("retention") == "reference" and locator.is_file():
        actual = ri.sha256_file(locator)
        if actual != source.get("sha256"):
            raise ri.ReviewIntakeError(
                "source_integrity_mismatch",
                "referenced review source changed after intake",
            )


def apply_decisions_to_path(root, review_id, decisions_path, write=False):
    if not ri.REVIEW_ID_RE.fullmatch(str(review_id or "")):
        raise ri.ReviewIntakeError(
            "review_id_invalid",
            "review_id must be a safe 3-128 character artifact identifier",
        )
    packet_path = (
        Path(root).resolve()
        / "workspace"
        / "reviews"
        / f"{review_id}.json"
    )
    packet = _load_json(packet_path)
    _verify_reference_integrity(packet)
    decisions = _load_json(decisions_path).get("decisions") or []
    if not isinstance(decisions, list):
        raise ri.ReviewIntakeError(
            "decisions_invalid", "decisions must be a list"
        )
    for decision in decisions:
        packet = ri.apply_decision(packet, decision)
    if not write:
        return {"action": "preview", "packet": _public_packet(packet)}
    paths = write_review_artifacts(root, packet)
    return {
        "action": "written",
        "packet": _public_packet(packet),
        "paths": {key: str(value) for key, value in paths.items()},
    }


def run_validation(packet, final=False):
    errors = ri.validate_packet(packet, final=final)
    return {"action": "validated", "valid": not errors, "errors": errors}


def build_parser():
    parser = argparse.ArgumentParser(
        description="Verified ModuFlow code-review intake"
    )
    parser.add_argument("project_path", nargs="?", default=".")
    operation = parser.add_mutually_exclusive_group(required=True)
    operation.add_argument("--new", action="store_true")
    operation.add_argument("--apply-decisions")
    operation.add_argument("--validate")
    parser.add_argument("--review-id")
    parser.add_argument(
        "--adapter", choices=["manual", "github", "codeql", "sarif"]
    )
    parser.add_argument("--source")
    parser.add_argument("--findings-file")
    parser.add_argument("--source-kind", choices=sorted(ri.SOURCE_KINDS))
    parser.add_argument("--provider", default="unknown")
    parser.add_argument("--source-identity", default="unknown")
    parser.add_argument("--received-at", default=date.today().isoformat())
    parser.add_argument(
        "--retention", choices=sorted(ri.RETENTION_MODES), default="reference"
    )
    parser.add_argument("--source-hash")
    parser.add_argument("--target-repository")
    parser.add_argument("--target-commit")
    parser.add_argument("--base-branch", default="main")
    parser.add_argument("--final", action="store_true")
    parser.add_argument("--write", action="store_true")
    return parser


def main(argv=None):
    args = build_parser().parse_args(argv)
    root = Path(args.project_path).resolve()
    try:
        if args.new:
            result = run_new_intake(root, args)
        elif args.apply_decisions:
            if not args.review_id:
                raise ri.ReviewIntakeError(
                    "usage_error", "--apply-decisions requires --review-id"
                )
            result = apply_decisions_to_path(
                root,
                args.review_id,
                args.apply_decisions,
                write=args.write,
            )
        else:
            result = run_validation(_load_json(args.validate), final=args.final)
        print(json.dumps(result, ensure_ascii=False, indent=2))
        return 0 if result.get("valid", True) else 1
    except (OSError, json.JSONDecodeError, ri.ReviewIntakeError) as exc:
        code = getattr(exc, "code", "review_intake_error")
        print(
            json.dumps(
                {"action": "error", "reason_code": code, "error": str(exc)},
                ensure_ascii=False,
            )
        )
        return 2


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Pure domain model for verified ModuFlow review intake packets."""

import copy
import hashlib
import json
import re
from datetime import date
from pathlib import Path
from urllib.parse import urlsplit, urlunsplit


REVIEW_SCHEMA = "moduflow.review-intake.v1"
SOURCE_KINDS = {"human", "ai", "tool"}
RETENTION_MODES = {"copy", "reference", "hash_only"}
VERIFICATION_STATES = {"unverified", "confirmed", "contradicted", "inconclusive"}
FINAL_DISPOSITIONS = {"accept", "partial_accept", "defer", "reject"}
LANES = {"security", "pre_release", "post_release_refactor"}
SEVERITIES = {"low", "medium", "high", "critical"}
REVIEW_ID_RE = re.compile(r"[0-9A-Za-z][0-9A-Za-z._-]{2,127}")
SHA256_RE = re.compile(r"[0-9a-f]{64}")
COMMIT_RE = re.compile(r"[0-9a-f]{40}")
SENSITIVE_PATH_PARTS = (
    "auth",
    "permission",
    "payment",
    "billing",
    "secret",
    "upload",
    "deploy",
    ".github/workflows",
)


class ReviewIntakeError(ValueError):
    """A review-intake validation error with a stable reason code."""

    def __init__(self, code, message):
        super().__init__(message)
        self.code = code


def _sha256_bytes(value):
    return hashlib.sha256(value).hexdigest()


def sha256_file(path):
    return _sha256_bytes(Path(path).read_bytes())


def _safe_locator(value):
    text = str(value or "")
    parsed = urlsplit(text)
    if parsed.scheme.lower() in {"http", "https"}:
        host = (parsed.hostname or "").lower()
        port = f":{parsed.port}" if parsed.port else ""
        return urlunsplit((parsed.scheme.lower(), host + port, parsed.path, "", ""))
    return text


def build_source_record(
    kind,
    provider,
    identity,
    received_at,
    retention,
    locator=None,
    copied_text=None,
    source_hash=None,
    model=None,
    version=None,
    policy_version=None,
):
    if kind not in SOURCE_KINDS:
        raise ReviewIntakeError(
            "source_kind_invalid", f"unsupported source kind: {kind}"
        )
    if retention not in RETENTION_MODES:
        raise ReviewIntakeError(
            "retention_invalid", f"unsupported retention: {retention}"
        )

    record = {
        "kind": kind,
        "provider": str(provider or "unknown"),
        "identity": str(identity or "unknown"),
        "received_at": str(received_at),
        "retention": retention,
    }
    optional = {
        "model": model,
        "version": version,
        "policy_version": policy_version,
    }
    for key, value in optional.items():
        if value:
            record[key] = str(value)

    if retention == "reference":
        path = Path(str(locator or ""))
        if path.is_file():
            record.update(
                locator=_safe_locator(path.resolve()),
                sha256=sha256_file(path),
            )
        elif re.match(r"^https?://", str(locator or "")) and SHA256_RE.fullmatch(
            str(source_hash or "")
        ):
            record.update(locator=_safe_locator(locator), sha256=source_hash)
        else:
            raise ReviewIntakeError(
                "source_unavailable",
                "reference requires a readable local file or URL plus SHA-256",
            )
    elif retention == "copy":
        if copied_text is None:
            raise ReviewIntakeError(
                "source_copy_missing", "copy retention requires copied text"
            )
        text = str(copied_text)
        record.update(
            copied_text=text,
            sha256=_sha256_bytes(text.encode("utf-8")),
        )
    else:
        digest = str(source_hash or "")
        if not SHA256_RE.fullmatch(digest):
            raise ReviewIntakeError(
                "source_hash_invalid",
                "hash_only requires a lowercase SHA-256",
            )
        record["sha256"] = digest
        if locator:
            record["description"] = _safe_locator(locator)

    return record


def _normalized_location(location):
    if not isinstance(location, dict):
        raise ReviewIntakeError(
            "finding_location_invalid", "finding locations must be objects"
        )
    path = str(location.get("path") or "").replace("\\", "/")
    while path.startswith("./"):
        path = path[2:]
    if not path or ".." in Path(path).parts or path.startswith("/"):
        raise ReviewIntakeError(
            "finding_path_invalid", "finding path must remain inside the project"
        )
    line = location.get("line")
    if line is not None and (not isinstance(line, int) or line < 1):
        raise ReviewIntakeError(
            "finding_line_invalid", "finding line must be a positive integer"
        )
    return {
        "path": path,
        "line": line,
        "anchor": str(location.get("anchor") or ""),
    }


def _fingerprint(raw, source, target, locations):
    stable = {
        "provider": source.get("provider", "unknown"),
        "rule_id": raw.get("rule_id") or "",
        "provider_fingerprint": raw.get("provider_fingerprint") or "",
        "repository": str(target["repository"]).lower(),
        "locations": [
            {"path": item["path"], "anchor": item["anchor"]}
            for item in locations
        ],
        "observation": re.sub(
            r"\s+",
            " ",
            str(raw.get("observation") or "").strip().lower(),
        ),
    }
    encoded = json.dumps(
        stable, ensure_ascii=False, sort_keys=True, separators=(",", ":")
    ).encode("utf-8")
    return "sha256:" + _sha256_bytes(encoded)


def normalize_finding(raw, index, source, target):
    if not isinstance(raw, dict):
        raise ReviewIntakeError("finding_invalid", "each finding must be an object")
    locations = [
        _normalized_location(item) for item in raw.get("locations", [])
    ]
    observation = str(raw.get("observation") or "").strip()
    if not observation:
        raise ReviewIntakeError(
            "observation_missing", "each finding requires an observation"
        )
    severity = str(raw.get("severity") or "medium").lower()
    if severity not in SEVERITIES:
        raise ReviewIntakeError(
            "severity_invalid", f"unsupported severity: {severity}"
        )

    source_author = raw.get("source_author") or {
        "kind": source["kind"],
        "identity": source["identity"],
    }
    router = raw.get("router") or {
        "classification": "unclassified",
        "confidence": "low",
        "proposed_lane": None,
        "reason_codes": [],
        "actor": None,
    }
    no_risk_claim = bool(raw.get("no_risk_claim"))
    return {
        "id": f"F-{index:03d}",
        "fingerprint": _fingerprint(raw, source, target, locations),
        "rule_id": raw.get("rule_id"),
        "source_author": copy.deepcopy(source_author),
        "observation": observation,
        "recommendation": str(raw.get("recommendation") or "").strip(),
        "root_cause_hypothesis": str(
            raw.get("root_cause_hypothesis") or ""
        ).strip(),
        "reviewer_confidence": str(
            raw.get("reviewer_confidence") or "unknown"
        ),
        "locations": locations,
        "provider_evidence": copy.deepcopy(raw.get("provider_evidence") or {}),
        "verification": {
            "state": "unverified",
            "verifier": None,
            "files_checked": [],
            "reproduction": [],
            "tests": [],
            "architecture": [],
            "import_boundaries": [],
            "contradictions": [],
            "verified_at": None,
        },
        "risk": {
            "severity": severity,
            "release_impact": raw.get("release_impact", "unknown"),
            "no_risk_claim": no_risk_claim,
            "no_risk_state": "unverified" if no_risk_claim else "not_claimed",
        },
        "router": copy.deepcopy(router),
        "disposition": {
            "state": "pending_verification",
            "rationale": "",
            "decided_by": None,
            "decided_at": None,
            "human_approved": False,
        },
        "decision_history": [],
        "route": {
            "lane": None,
            "CognitiveDemand": None,
            "candidate_ids": [],
            "existing_issue_ids": [],
        },
    }


def new_packet(review_id, source, target, trigger, adapter_run, raw_findings):
    packet = {
        "schema": REVIEW_SCHEMA,
        "review_id": str(review_id),
        "source": copy.deepcopy(source),
        "target": copy.deepcopy(target),
        "trigger": copy.deepcopy(trigger),
        "adapter_run": copy.deepcopy(adapter_run),
        "findings": [
            normalize_finding(raw, index, source, target)
            for index, raw in enumerate(raw_findings, 1)
        ],
        "trace": {
            "finding_to_candidates": {},
            "candidate_to_findings": {},
        },
        "updated_at": date.today().isoformat(),
    }
    errors = validate_packet(packet)
    if errors:
        raise ReviewIntakeError(errors[0]["code"], errors[0]["message"])
    return packet


def validate_packet(packet, final=False):
    errors = []

    def add(code, path, message):
        errors.append({"code": code, "path": path, "message": message})

    if not isinstance(packet, dict):
        add("packet_invalid", "$", "packet must be an object")
        return errors
    if packet.get("schema") != REVIEW_SCHEMA:
        add("schema_invalid", "schema", f"expected {REVIEW_SCHEMA}")
    if not REVIEW_ID_RE.fullmatch(str(packet.get("review_id") or "")):
        add(
            "review_id_invalid",
            "review_id",
            "review_id must be a safe 3-128 character artifact identifier",
        )

    source = packet.get("source") or {}
    if source.get("kind") not in SOURCE_KINDS:
        add(
            "source_kind_invalid",
            "source.kind",
            "source kind must be human, ai, or tool",
        )
    if source.get("retention") not in RETENTION_MODES:
        add(
            "retention_invalid",
            "source.retention",
            "source retention must be copy, reference, or hash_only",
        )
    if not SHA256_RE.fullmatch(str(source.get("sha256") or "")):
        add(
            "source_hash_invalid",
            "source.sha256",
            "source requires a lowercase SHA-256",
        )
    if source.get("retention") == "reference" and not source.get("locator"):
        add(
            "source_reference_missing",
            "source.locator",
            "reference retention requires a locator",
        )

    target = packet.get("target") or {}
    if not target.get("repository") or not COMMIT_RE.fullmatch(
        str(target.get("commit") or "")
    ):
        add(
            "target_unverifiable",
            "target",
            "repository and full commit SHA are required",
        )

    finding_ids = set()
    for index, finding in enumerate(packet.get("findings") or []):
        path = f"findings[{index}]"
        finding_id = finding.get("id")
        if not finding_id or finding_id in finding_ids:
            add("finding_id_invalid", path + ".id", "finding IDs must be unique")
        finding_ids.add(finding_id)
        if not str(finding.get("fingerprint") or "").startswith("sha256:"):
            add(
                "finding_fingerprint_invalid",
                path + ".fingerprint",
                "finding requires a SHA-256 fingerprint",
            )
        if not finding.get("observation"):
            add(
                "observation_missing",
                path + ".observation",
                "finding requires an observation",
            )
        if finding.get("verification", {}).get("state") not in VERIFICATION_STATES:
            add(
                "verification_state_invalid",
                path + ".verification.state",
                "unsupported verification state",
            )
        disposition_record = finding.get("disposition") or {}
        disposition = disposition_record.get("state")
        if final and disposition not in FINAL_DISPOSITIONS:
            add(
                "disposition_pending",
                path + ".disposition.state",
                "final packets require a disposition",
            )
        elif final:
            if not str(disposition_record.get("rationale") or "").strip():
                add(
                    "disposition_rationale_missing",
                    path + ".disposition.rationale",
                    "final dispositions require rationale",
                )
            verification_state = finding.get("verification", {}).get("state")
            if disposition == "accept" and verification_state != "confirmed":
                add(
                    "accept_requires_evidence",
                    path + ".verification.state",
                    "accept requires confirmed evidence",
                )
            if disposition == "partial_accept":
                if verification_state not in {"confirmed", "inconclusive"}:
                    add(
                        "partial_accept_requires_evidence",
                        path + ".verification.state",
                        "partial accept requires confirmed or inconclusive evidence",
                    )
                if not str(
                    disposition_record.get("accepted_scope") or ""
                ).strip():
                    add(
                        "partial_accept_scope_missing",
                        path + ".disposition.accepted_scope",
                        "partial accept requires the accepted observation or scope",
                    )
    return errors


def evaluate_policy(finding):
    """Return deterministic routing and approval requirements for a finding."""
    paths = [
        item["path"].lower() for item in finding.get("locations", [])
    ]
    severity = finding.get("risk", {}).get("severity", "medium")
    sensitive = any(
        any(part in path for part in SENSITIVE_PATH_PARTS) for path in paths
    )
    security_signal = (
        sensitive
        or finding.get("router", {}).get("classification") == "security"
        or finding.get("provider_evidence", {}).get("kind") == "security"
    )
    reasons = []
    if sensitive:
        reasons.append("sensitive_path")
    if severity in {"high", "critical"}:
        reasons.append("elevated_severity")

    verification = finding.get("verification") or {}
    if finding.get("risk", {}).get("no_risk_claim") and not (
        verification.get("tests") and verification.get("import_boundaries")
    ):
        reasons.append("no_risk_evidence_missing")

    if security_signal:
        lane = "security"
    elif (
        severity in {"high", "critical"}
        or finding.get("risk", {}).get("release_impact") == "blocking"
    ):
        lane = "pre_release"
    else:
        lane = "post_release_refactor"

    if lane == "security" or verification.get("architecture"):
        cognitive_demand = "deep"
    elif lane == "pre_release":
        cognitive_demand = "balanced"
    else:
        cognitive_demand = "fast"

    router = finding.get("router") or {}
    return {
        "lane": lane,
        "CognitiveDemand": cognitive_demand,
        "requires_verifier": (
            severity in {"medium", "high", "critical"}
            or router.get("confidence") != "high"
        ),
        "requires_human_for_reject": (
            severity in {"high", "critical"} or lane == "security"
        ),
        "reason_codes": reasons,
    }


def _provenance_key(actor):
    actor = actor or {}
    return (
        actor.get("kind"),
        actor.get("identity"),
        actor.get("run_id"),
    )


def _actor_identity(actor):
    actor = actor or {}
    return (actor.get("kind"), actor.get("identity"))


def _normalized_verification(decision):
    verification = copy.deepcopy(decision.get("verification") or {})
    state = verification.get("state")
    if state not in VERIFICATION_STATES:
        raise ReviewIntakeError(
            "verification_state_invalid",
            "decision requires a valid verification state",
        )
    verification.setdefault("verifier", None)
    for key in (
        "files_checked",
        "reproduction",
        "tests",
        "architecture",
        "import_boundaries",
        "contradictions",
    ):
        value = verification.setdefault(key, [])
        if not isinstance(value, list):
            raise ReviewIntakeError(
                "verification_evidence_invalid",
                f"verification {key} must be a list",
            )
    verification.setdefault("verified_at", date.today().isoformat())
    return verification


def apply_decision(packet, decision):
    """Apply one evidence-backed disposition and return a new packet."""
    updated = copy.deepcopy(packet)
    if decision.get("target_commit") != updated.get("target", {}).get("commit"):
        raise ReviewIntakeError(
            "target_commit_mismatch",
            "decision target commit differs from the reviewed commit",
        )

    finding = next(
        (
            item
            for item in updated.get("findings", [])
            if item.get("id") == decision.get("finding_id")
        ),
        None,
    )
    if finding is None:
        raise ReviewIntakeError(
            "finding_not_found", "decision finding does not exist"
        )

    verification = _normalized_verification(decision)
    disposition = decision.get("disposition")
    if disposition not in FINAL_DISPOSITIONS:
        raise ReviewIntakeError(
            "disposition_invalid", "decision requires a final disposition"
        )
    rationale = str(decision.get("rationale") or "").strip()
    if not rationale:
        raise ReviewIntakeError(
            "disposition_rationale_missing",
            "every disposition requires rationale",
        )
    accepted_scope = str(decision.get("accepted_scope") or "").strip()
    if disposition == "partial_accept" and not accepted_scope:
        raise ReviewIntakeError(
            "partial_accept_scope_missing",
            "partial accept requires the accepted observation or scope",
        )
    state = verification["state"]
    if disposition == "accept" and state != "confirmed":
        raise ReviewIntakeError(
            "accept_requires_evidence", "accept requires confirmed evidence"
        )
    if disposition == "partial_accept" and state not in {
        "confirmed",
        "inconclusive",
    }:
        raise ReviewIntakeError(
            "partial_accept_requires_evidence",
            "partial accept requires confirmed or inconclusive evidence",
        )

    finding["verification"] = verification
    policy = evaluate_policy(finding)
    verifier = verification.get("verifier") or {}
    if policy["requires_verifier"]:
        if verifier.get("role") != "verifier" or not verifier.get("identity"):
            raise ReviewIntakeError(
                "verifier_missing",
                "policy requires explicit verifier provenance",
            )
        source_identity = _actor_identity(finding.get("source_author"))
        router_key = _provenance_key(
            finding.get("router", {}).get("actor")
        )
        same_source_reviewer = (
            any(source_identity)
            and _actor_identity(verifier) == source_identity
        )
        same_router_run = (
            any(router_key) and _provenance_key(verifier) == router_key
        )
        if same_source_reviewer or same_router_run:
            raise ReviewIntakeError(
                "verifier_not_independent",
                "verifier must differ from source reviewer and Router run",
            )

    actor = copy.deepcopy(
        decision.get("actor") or {"kind": "unknown", "identity": "unknown"}
    )
    human_approved = bool(decision.get("human_approved"))
    if (
        disposition == "reject"
        and policy["requires_human_for_reject"]
        and not human_approved
    ):
        raise ReviewIntakeError(
            "high_risk_reject_requires_human",
            "high-risk rejection requires human approval",
        )

    if finding["risk"].get("no_risk_claim"):
        finding["risk"]["no_risk_state"] = (
            "verified"
            if verification["tests"] and verification["import_boundaries"]
            else "unverified"
        )

    event = {
        "state": disposition,
        "rationale": rationale,
        "decided_by": actor,
        "decided_at": date.today().isoformat(),
        "human_approved": human_approved,
        "accepted_scope": accepted_scope or None,
    }
    finding.setdefault("decision_history", []).append(copy.deepcopy(event))
    finding["disposition"] = event
    if disposition in {"accept", "partial_accept"}:
        finding["route"].update(
            lane=policy["lane"],
            CognitiveDemand=policy["CognitiveDemand"],
        )
    else:
        finding["route"].update(lane=None, CognitiveDemand=None)
    finding["policy"] = policy
    updated["updated_at"] = date.today().isoformat()
    return updated


def _candidate_fingerprint(findings):
    fingerprints = sorted(finding["fingerprint"] for finding in findings)
    if len(fingerprints) == 1:
        return fingerprints[0]
    return "sha256:" + _sha256_bytes("|".join(fingerprints).encode("utf-8"))


def _candidate_lane(findings):
    lanes = {finding["route"]["lane"] for finding in findings}
    if "security" in lanes:
        return "security"
    if "pre_release" in lanes:
        return "pre_release"
    return "post_release_refactor"


def _candidate_demand(findings):
    rank = {"fast": 0, "balanced": 1, "deep": 2}
    return max(
        (finding["route"]["CognitiveDemand"] for finding in findings),
        key=lambda value: rank[value],
    )


def _candidate_priority(findings):
    priorities = []
    for finding in findings:
        if finding["risk"]["severity"] == "critical":
            priorities.append("p0")
        elif finding["route"]["lane"] in {"security", "pre_release"}:
            priorities.append("p1")
        else:
            priorities.append("p2")
    rank = {"p2": 0, "p1": 1, "p0": 2}
    return max(priorities, key=lambda value: rank[value])


def build_candidates(packet, existing_candidates=(), proposals=()):
    """Build local remediation candidates and bidirectional trace metadata."""
    existing_by_fingerprint = {
        item.get("fingerprint"): item
        for item in existing_candidates
        if item.get("fingerprint")
    }
    accepted = {
        item["id"]: item
        for item in packet.get("findings", [])
        if item.get("disposition", {}).get("state")
        in {"accept", "partial_accept"}
    }
    candidate_specs = list(proposals) or []
    if not candidate_specs:
        for finding_id, finding in accepted.items():
            if finding["disposition"]["state"] == "partial_accept":
                title = finding["disposition"]["accepted_scope"]
            else:
                title = finding["recommendation"] or finding["observation"]
            candidate_specs.append(
                {"title": title, "finding_ids": [finding_id]}
            )
    candidates = []
    finding_to_candidates = {finding_id: [] for finding_id in accepted}
    candidate_to_findings = {}

    for spec in candidate_specs:
        finding_ids = list(dict.fromkeys(spec.get("finding_ids") or []))
        if not finding_ids or any(
            finding_id not in accepted for finding_id in finding_ids
        ):
            raise ReviewIntakeError(
                "candidate_finding_invalid",
                "candidate proposals must reference accepted findings",
            )
        findings = [accepted[finding_id] for finding_id in finding_ids]
        fingerprint = _candidate_fingerprint(findings)
        existing = existing_by_fingerprint.get(fingerprint)
        candidate_id = (
            f"{packet['review_id']}-RC-{len(candidates) + 1:03d}"
        )
        existing_issue_ids = (
            list(existing.get("existing_issue_ids") or []) if existing else []
        )
        if (
            existing
            and existing.get("issue_id")
            and existing["issue_id"] not in existing_issue_ids
        ):
            existing_issue_ids.append(existing["issue_id"])

        dependencies = list(spec.get("dependencies") or [])
        if not dependencies:
            dependencies = sorted(
                {
                    dependency
                    for finding in findings
                    for dependency in (
                        finding.get("router", {}).get("dependency_hints") or []
                    )
                }
            )
        reason_codes = sorted(
            {
                reason
                for finding in findings
                for reason in (
                    (finding.get("router", {}).get("reason_codes") or [])
                    + (finding.get("policy", {}).get("reason_codes") or [])
                )
            }
        )
        title = str(
            spec.get("title")
            or findings[0]["recommendation"]
            or findings[0]["observation"]
        )
        candidate = {
            "id": candidate_id,
            "state": "linked_existing" if existing else "candidate",
            "title": title[:100],
            "problem": "\n".join(
                finding["observation"] for finding in findings
            ),
            "scope": sorted(
                {
                    location["path"]
                    for finding in findings
                    for location in finding.get("locations", [])
                }
            ),
            "acceptance_evidence": {
                finding["id"]: copy.deepcopy(finding["verification"])
                for finding in findings
            },
            "priority": _candidate_priority(findings),
            "dependencies": dependencies,
            "CognitiveDemand": _candidate_demand(findings),
            "routing_reason_codes": reason_codes,
            "lane": _candidate_lane(findings),
            "release_impact": (
                "blocking"
                if any(
                    finding["risk"]["release_impact"] == "blocking"
                    for finding in findings
                )
                else "non_blocking"
            ),
            "finding_ids": finding_ids,
            "fingerprint": fingerprint,
            "existing_issue_ids": existing_issue_ids,
            "linked_candidate_id": existing.get("id") if existing else None,
            "overlap_hints": [],
            "next_command": (
                f"product:issue {existing_issue_ids[0]}"
                if existing_issue_ids
                else (
                    "product:review --intake"
                    if existing
                    else "product:issue"
                )
            ),
        }
        candidates.append(candidate)
        for finding_id in finding_ids:
            finding_to_candidates[finding_id].append(candidate_id)
        candidate_to_findings[candidate_id] = finding_ids

    if any(
        not candidate_ids for candidate_ids in finding_to_candidates.values()
    ):
        raise ReviewIntakeError(
            "accepted_finding_unmapped",
            "every accepted finding must map to a candidate",
        )
    return {
        "candidates": candidates,
        "trace": {
            "finding_to_candidates": finding_to_candidates,
            "candidate_to_findings": candidate_to_findings,
        },
    }

